            if (this.reimbursementBalances && this.reimbursementBalances.accounts && this.reimbursementBalances.accounts.length > 0) {
                return true;
            }
            return this.$store.getters.config?.plus_account?.automatic_reimbursement_signed_at;
        },
        hasTerminatedAgreement() {
            // Check reimbursement balances first
            if (this.reimbursementBalances && this.reimbursementBalances.accounts && this.reimbursementBalances.accounts.length > 0) {
                const firstAccount = this.reimbursementBalances.accounts[0];
                if (firstAccount.data_dump_json) {
                    try {
                        const dataDump = JSON.parse(firstAccount.data_dump_json);
                        return !!(dataDump.automatic_reimbursement_terminated_at && dataDump.automatic_reimbursement_terminated_at !== 0);
                    } catch (e) {
                        console.error('Error parsing data_dump_json:', e);
                    }
                }
            }
            return this.$store.getters.config?.plus_account?.automatic_reimbursement_terminated_at;
        },
        agreementDetails() {
            // Try to get agreement details from reimbursement balances first
            if (this.reimbursementBalances && this.reimbursementBalances.accounts && this.reimbursementBalances.accounts.length > 0) {
                // Use the first account's data_dump_json
                const firstAccount = this.reimbursementBalances.accounts[0];
                if (firstAccount.data_dump_json) {
                    try {
                        const dataDump = JSON.parse(firstAccount.data_dump_json);
                        return {
                            name: dataDump.automatic_reimbursement_name || '',
                            address: dataDump.automatic_reimbursement_address || '',
                            country: dataDump.automatic_reimbursement_country || '',
                            index: dataDump.automatic_reimbursement_index || '',
                            city: dataDump.automatic_reimbursement_city || '',
                            state: dataDump.automatic_reimbursement_state || '',
                            bank_details: dataDump.automatic_reimbursement_bank_details || '',
                            tax_id: dataDump.automatic_reimbursement_tax_id || '',
                            signed_at: dataDump.automatic_reimbursement_signed_at || 0,
                            terminated_at: dataDump.automatic_reimbursement_terminated_at || 0
                        };
                    } catch (e) {
                        console.error('Error parsing data_dump_json:', e);
                    }
                }
            }
            // Fallback to store config
            const plusAccount = this.$store.getters.config?.plus_account || {};
            return {
                name: plusAccount.automatic_reimbursement_name || '',
                address: plusAccount.automatic_reimbursement_address || '',
                country: plusAccount.automatic_reimbursement_country || '',
                index: plusAccount.automatic_reimbursement_index || '',
                city: plusAccount.automatic_reimbursement_city || '',
                state: plusAccount.automatic_reimbursement_state || '',
                bank_details: plusAccount.automatic_reimbursement_bank_details || '',
                tax_id: plusAccount.automatic_reimbursement_tax_id || '',
                signed_at: plusAccount.automatic_reimbursement_signed_at || 0,
                terminated_at: plusAccount.automatic_reimbursement_terminated_at || 0
            };
        },
        deviceResetAt() {
            return this.$store.getters.config?.plus_account?.device_reset_at || null;
        },
        formatDeviceResetDate() {
            if (!this.deviceResetAt) return '';
            return new Date(this.deviceResetAt * 1000).toLocaleDateString();
        },
        formattedSignedDate() {
            const signedAt = this.agreementDetails.signed_at;
            if (!signedAt || signedAt === 0) return '';
            const timestamp = typeof signedAt === 'string' ? parseInt(signedAt) : signedAt;
            const date = new Date(timestamp * 1000);
            return date.toLocaleString();
        },
        formattedTerminatedDate() {
            const terminatedAt = this.agreementDetails.terminated_at;
            if (!terminatedAt || terminatedAt === 0) return '';
            const timestamp = typeof terminatedAt === 'string' ? parseInt(terminatedAt) : terminatedAt;
            const date = new Date(timestamp * 1000);
            return date.toLocaleString();
        },
        deviceCount() {
            return this.$store.getters.config?.plus_account?.automatic_reimbursement_devices_amount || 0;
        },
        isDevicesView() {
            return this.$route.path.includes('/devices');
        },
        currentAccountId() {
            const match = this.$route.path.match(/\/devices\/(\d+)/);
            return match ? parseInt(match[1]) : null;
        },
        isMobile() {
            return window.innerWidth < 768;
        },
        financialDetails() {
            if (this.reimbursementBalances?.totals) {
                const totals = this.reimbursementBalances.totals;
                return {
                    balance: this.formatCurrency(totals.total_balance || 0),
                    availableForWithdrawal: this.formatCurrency(totals.total_available_for_withdrawal),
                    withdrawalPending: this.formatCurrency(totals.total_pending_withdrawals),
                    withdrawalCompleted: this.formatCurrency(totals.total_completed_withdrawals)
                };
            }
            const plusAccount = this.$store.getters.config?.plus_account || {};
            return {
                balance: this.formatCurrency(plusAccount.automatic_reimbursement_balance_eur || 0),
                availableForWithdrawal: this.formatCurrency(plusAccount.automatic_reimbursement_available_for_withdrawal_eur || 0),
                withdrawalPending: this.formatCurrency(plusAccount.automatic_reimbursement_withdrawal_pending_eur || 0),
                withdrawalCompleted: this.formatCurrency(plusAccount.automatic_reimbursement_withdrawal_completed_eur || 0)
            };
        },
        accounts() {
            return this.reimbursementBalances?.accounts || [];
        },
        availableSlots() {
            const plusAccount = this.$store.getters.config?.plus_account || {};
            const usedSlots = parseInt(plusAccount.used_slots) || 0;
            const p2pDevicesLimit = this.$store.state.stats?.p2p_devices_limit;
            var to_return = p2pDevicesLimit - usedSlots;
            if (to_return < 0) {
                to_return = 0;
            }
            return to_return;
        },
        isWithdrawalsView() {
            return this.$route.path.endsWith('/withdrawals');
        },
        isDeviceLinked() {
            return this.$store.getters.isDeviceLinked;
        }
    },
    watch: {
        isDevicesView(newVal) {
            if (newVal && this.isDeviceLinked) {
                this.loadDevices();
            }
        },
        currentAccountId() {
            if (this.isDevicesView && this.isDeviceLinked) {
                this.loadDevices();
            }
        },
        isWithdrawalsView(newVal) {
            if (newVal && this.withdrawals.length === 0 && this.isDeviceLinked) {
                this.loadWithdrawals();
            }
        }
    },
    created() {
        this.isLoading = true;

        // Fetch stats if not already available
        this.$store.dispatch('getStats').catch((error) => {
            console.error('Error fetching stats:', error);
        });

        Promise.all([
            this.$api.post('get_defaults', { 'for': 'auto_reimbursement_md' }, false),
            this.isDeviceLinked ? this.loadReimbursementBalances() : Promise.resolve()
        ])
            .then(([response]) => {
                if (response.success && response.data) {
                    this.contract = response.data.contract || '';
                } else {
                    console.error('Failed to fetch markdown content:', response);
                }
            })
            .catch((error) => {
                console.error('Error fetching data:', error);
            })
            .finally(() => {
                this.isLoading = false;

                // Load appropriate data based on the current route and device linkage
                if (this.isDeviceLinked) {
                    if (this.isDevicesView) {
                        this.loadDevices();
                    } else if (this.isWithdrawalsView) {
                        this.loadWithdrawals();
                    }
                }
            });
    },
    methods: {
        formatCurrency(value) {
            const num = parseFloat(value) || 0;
            return num.toFixed(2);
        },
        toggleAgreementText() {
            this.showAgreementText = !this.showAgreementText;
        },
        submitForm() {
            if (this.submitting) return;

            this.submitting = true;

            // When handleErrors is true (the 3rd parameter), the API service will:
            // 1. Show error notifications automatically
            // 2. Throw an error when result.success is false
            // 3. Only return result.data on success (not the full response with success property)
            this.$api.post('edit_plus_dev_account_reimbursement_settings', {
                name: this.formData.name,
                address: this.formData.address,
                country: this.formData.country,
                index: this.formData.index,
                city: this.formData.city,
                state: this.formData.state,
                bank_details: this.formData.bank_details,
                tax_id: this.formData.tax_id
            }, true) // Setting handleErrors to true
                .then(() => { // We get data directly, not a response object with success property
                    // Update device information using the correct store actions
                    // First get the configuration which includes plus_account details
                    return this.$store.dispatch('getConfig')
                        .then(() => {
                            // Then get updated devices information
                            return this.$store.dispatch('getDevices');
                        })
                        .then(() => {
                            Vue.notify({
                                type: 'success',
                                text: 'Agreement has been successfully signed'
                            });
                        });
                })
                .catch((error) => {
                    // The API service already showed an error notification
                    console.error('Error submitting form:', error);
                })
                .finally(() => {
                    this.submitting = false;
                });
        },
        loadDevices() {
            this.loadingDevices = true;

            // Load reimbursement balances to get devices for the account
            const loadDevicesFromBalances = () => {
                if (this.reimbursementBalances) {
                    const accountId = this.currentAccountId;
                    if (accountId) {
                        // Find the specific account
                        const account = this.reimbursementBalances.accounts.find(acc => acc.id === accountId);
                        if (account) {
                            this.devices = account.devices || [];
                        } else {
                            this.devices = [];
                        }
                    } else {
                        // If no account_id, show devices from all accounts
                        this.devices = this.reimbursementBalances.accounts.flatMap(acc => acc.devices || []);
                    }
                    this.loadingDevices = false;
                } else {
                    // Load balances first if not loaded
                    this.loadReimbursementBalances().then(() => {
                        loadDevicesFromBalances();
                    }).catch((error) => {
                        console.error('Error loading reimbursement balances:', error);
                        Vue.notify({
                            type: 'error',
                            text: 'Failed to load registered devices'
                        });
                        this.devices = [];
                        this.loadingDevices = false;
                    });
                }
            };

            loadDevicesFromBalances();
        },
        getActiveDevicesCount(account) {
            if (!account || !account.devices) return 0;
            const now = Date.now();
            return account.devices.filter(device => device.expires_at * 1000 > now).length;
        },
        getAvailableDevicesCount(account) {
            if (!account || !account.devices) return 0;
            if (account.is_archived) return 0;
            const p2pDevicesLimit = this.$store.state.stats?.p2p_devices_limit || 0;
            const available = p2pDevicesLimit - account.devices.length;
            return available > 0 ? available : 0;
        },
        getAccountById(accountId) {
            if (!this.reimbursementBalances || !this.reimbursementBalances.accounts) return null;
            return this.reimbursementBalances.accounts.find(acc => acc.id === accountId);
        },
        loadReimbursementBalances() {
            this.loadingBalances = true;
            return this.$api.getReimbursementBalances()
                .then((response) => {
                    if (response.success && response.data) {
                        this.reimbursementBalances = response.data;
                    }
                })
                .catch((error) => {
                    console.error('Error loading reimbursement balances:', error);
                })
                .finally(() => {
                    this.loadingBalances = false;
                });
        },
        loadWithdrawals() {
            this.loadingWithdrawals = true;

            this.$api.getWithdrawals()
                .then((response) => {
                    this.withdrawals = response.data || [];
                })
                .catch((error) => {
                    console.error('Error loading withdrawals:', error);
                    Vue.notify({
                        type: 'error',
                        text: 'Failed to load withdrawal history'
                    });
                })
                .finally(() => {
                    this.loadingWithdrawals = false;
                });
        },
        requestWithdrawal() {
            if (this.isWithdrawalProcessing) return;

            this.isWithdrawalProcessing = true;

            const amount = this.financialDetails.availableForWithdrawal;
            const confirmMessage = `Are you sure to withdraw €${amount} to your configured payment method?<br><br>If there is more than one developer account configured, multiple withdrawals will be made.`;

            this.$confirm(confirmMessage, { yesOrNo: true })
                .then(() => {
                    return this.$api.post('request_withdrawal', {}, true);
                })
                .then(() => {
                    // Refresh configuration data to update financial details
                    return this.$store.dispatch('getConfig');
                })
                .then(() => {
                    // Update device information
                    return this.$store.dispatch('getDevices');
                })
                .then(() => {
                    // On success and after refreshing data, redirect to withdrawals page
                    this.$router.push('/my/auto-reimbursement/withdrawals');
                })
                .catch((error) => {
                    // If it's a real error (not just cancellation of dialog), log it
                    if (error) {
                        console.error('Withdrawal request failed:', error);
                    }
                })
                .finally(() => {
                    this.isWithdrawalProcessing = false;
                });
        }
    }
};
</script>

